SELECT /* base.ec.pd :: PdhProdViewLog :: selectList */ l.* , ste.site_nm AS site_nm FROM pdh_prod_view_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.ref_nm ASC ORDER BY l.ref_nm DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pd :: PdhProdViewLog :: selectPageList */ l.* , ste.site_nm AS site_nm FROM pdh_prod_view_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.ref_nm ASC ORDER BY l.ref_nm DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
